mapper.select:
select ifnull(`order`.z_price,0) as z_price ,ifnull(`order`.z_freight,0) as z_freight,a.id,c.id goodsId,c.product_title,c.imgurl,c.num stockNum,a.team_num,d.user_name teamName,a.status,a.add_date, a.end_date as openEndDate, b.start_date,b.end_date, b.team_limit, a.team_commission,a.activity_id,b.team_rule,attr.price attr_price from lkt_group_open a left join lkt_order `order` on `order`.sno=a.sno inner join lkt_group_activity b on a.activity_id=b.id inner join lkt_product_list c on c.id = a.goods_id inner join lkt_user d on d.user_id= a.user_id inner join lkt_configure attr on attr.id=a.attr_id
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

select a.id,c.id goodsId,c.product_title,a.team_num,d.user_name teamName,a.status,a.add_date,b.start_date,b.end_date,a.team_commission from lkt_group_open a inner join lkt_group_activity b on a.activity_id=b.id inner join lkt_product_list c on c.id = a.goods_id inner join lkt_user d on d.user_id= a.user_id
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

