    and `open`.is_settlement = #{isSettlement}
    and a.otype = #{orderType}
    and `open`.status = #{teamStatus}
    and `open`.id = #{openId}
    and ac.status = #{acId}
    and a.user_id = #{userId}
    and c.id = #{goodsId}
    and a.store_id = #{storeId}
    and not exists(select x.id from lkt_group_open_record x where x.user_id=`open`.user_id and x.open_id=`open`.id and x.recycle=0)
    
      
        #{name}
      
    
    and `open`.add_date   >=   #{startDate}
    and `open`.add_date   <=   #{endDate}

mapper.select:
select a.id oid,a.sno,a.z_price,a.user_id,a.pay,a.spz_price,a.status orderStatus,a.arrive_time settleDate,b.p_name,attr.id attrId,attr.pid goodsId ,attr.img,a.add_time,a.arrive_time settelDate,mch.id mchId,mch.head_img mchImg,mch.`name` mchName,b.p_id,a.store_id,`open`.is_settlement, `open`.id openId,`open`.goods_id goodsId,b.size,`ac`.team_rule,`ac`.id acId,ac.status teamStatus,ac.name as activityName, `open`.status,`open`.team_num,`open`.user_id teamUserId,`open`.sno openNo,`user`.user_name,`user`.headimgurl,`open`.add_date openDate,`open`.end_date openEndDate,`open`.team_commission from lkt_order a inner join lkt_order_details b on a.sno=b.r_sno and a.recycle=b.recycle inner join lkt_group_open `open` on `open`.sno=a.sno inner join lkt_group_activity ac on `open`.activity_id=ac.id inner join lkt_user `user` on `user`.user_id = `open`.user_id inner join lkt_configure attr on attr.id=b.sid inner join lkt_product_list c on c.id = attr.pid left join lkt_mch mch on mch.id=c.mch_id
a.add_time ${add_date_sort},
limit #{pageStart},#{pageEnd}
